export const LOGIN_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>LogOS Core - Login</title>\n  <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n  <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n  <link href=\"https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Playfair+Display:wght@600;700&display=swap\" rel=\"stylesheet\">\n  <style>\n    :root {\n      /* Base */\n      --bg-base: #0b0d0e;\n      --bg-panel: #131618;\n      --bg-elevated: #1a1d21;\n\n      /* Ink */\n      --ink-primary: #e8e6e1;\n      --ink-secondary: #a0a0a5;\n      --ink-tertiary: #6e6e73;\n\n      /* Borders */\n      --border-subtle: #2a2d31;\n\n      /* Typography */\n      --font-serif: 'Playfair Display', serif;\n      --font-sans: 'Inter', sans-serif;\n\n      /* Radii */\n      --radius-md: 8px;\n      --radius-lg: 12px;\n\n      /* Brand */\n      --brand-gold: #d4af37;\n      --brand-primary: #d4af37;\n      --brand-dim: rgba(212, 175, 55, 0.2);\n      --brand-blue: #4da8da;\n    }\n\n    * {\n      box-sizing: border-box;\n      margin: 0;\n      padding: 0;\n    }\n\n    body {\n      background:\n        linear-gradient(135deg, rgba(212, 175, 55, 0.12), transparent 38%),\n        linear-gradient(315deg, rgba(77, 168, 218, 0.08), transparent 36%),\n        var(--bg-base);\n      color: var(--ink-primary);\n      font-family: var(--font-sans);\n      line-height: 1.5;\n      min-width: 320px;\n      min-height: 100vh;\n      min-height: 100svh;\n      display: flex;\n      flex-direction: column;\n      align-items: center;\n      justify-content: center;\n      padding: 16px;\n    }\n\n    .card {\n      background: rgba(19, 22, 24, 0.9);\n      border: 1px solid var(--border-subtle);\n      border-radius: var(--radius-lg);\n      padding: 48px;\n      width: 100%;\n      max-width: 420px;\n      text-align: center;\n      position: relative;\n      box-shadow: 0 24px 70px rgba(0, 0, 0, 0.34);\n      backdrop-filter: blur(18px);\n    }\n\n    .logo-container {\n      margin-bottom: 32px;\n    }\n\n    .logo-mark {\n      width: 56px;\n      height: 56px;\n      margin-bottom: 16px;\n      color: var(--brand-primary);\n    }\n\n    h1 {\n      font-family: var(--font-serif);\n      font-size: 1.45rem;\n      font-weight: 700;\n      line-height: 1;\n      color: var(--brand-primary);\n      margin-bottom: 4px;\n    }\n\n    .tagline {\n      font-family: var(--font-sans);\n      font-size: 0.85rem;\n      color: var(--ink-secondary);\n      margin-bottom: 0;\n    }\n\n    .brand-divider {\n      width: 72px;\n      height: 1px;\n      margin: 18px auto 0;\n      background: linear-gradient(90deg, transparent, var(--brand-primary), transparent);\n      opacity: 0.85;\n    }\n\n    .input-wrapper {\n      position: relative;\n      margin-bottom: 16px;\n    }\n\n    .email-label {\n      position: absolute;\n      top: -10px;\n      left: 12px;\n      background: var(--bg-panel);\n      padding: 0 4px;\n      font-size: 0.75rem;\n      color: var(--ink-secondary);\n    }\n\n    input[type=\"email\"] {\n      width: 100%;\n      background-color: var(--bg-elevated);\n      border: 1px solid var(--border-subtle);\n      border-radius: var(--radius-md);\n      padding: 12px 16px;\n      color: var(--ink-primary);\n      font-family: var(--font-sans);\n      font-size: 16px;\n      outline: none;\n      transition: all 0.2s ease;\n    }\n\n    input[type=\"email\"]::placeholder {\n      color: var(--ink-tertiary);\n    }\n\n    input[type=\"email\"]:focus {\n      border-color: var(--brand-primary);\n      box-shadow: 0 0 0 1px var(--brand-primary);\n    }\n\n    input[type=\"email\"]:disabled {\n      opacity: 0.5;\n      cursor: not-allowed;\n    }\n\n    button {\n      width: 100%;\n      background-color: var(--brand-primary);\n      color: #0b0d0e;\n      border: none;\n      border-radius: var(--radius-md);\n      padding: 12px;\n      min-height: 44px;\n      font-family: var(--font-sans);\n      font-size: 1rem;\n      font-weight: 600;\n      cursor: pointer;\n      transition: background-color 0.2s ease;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      -webkit-tap-highlight-color: transparent;\n    }\n\n    button:hover:not(:disabled) {\n      background-color: #e5c455;\n    }\n\n    button:active:not(:disabled) {\n      background-color: #c89f29;\n    }\n\n    button:focus-visible,\n    .send-again:focus-visible {\n      outline: none;\n      box-shadow: 0 0 0 1px var(--brand-primary);\n    }\n\n    button:disabled {\n      background-color: var(--brand-primary);\n      opacity: 0.5;\n      cursor: not-allowed;\n    }\n\n    /* States Wrapper */\n    .state {\n      display: none;\n      animation: fadeIn 0.3s ease-in-out forwards;\n    }\n\n    .state.active {\n      display: block;\n    }\n\n    @keyframes fadeIn {\n      from { opacity: 0; }\n      to { opacity: 1; }\n    }\n\n    /* Loading Spinner */\n    .spinner {\n      width: 20px;\n      height: 20px;\n      border: 2px solid rgba(11, 13, 14, 0.3);\n      border-top: 2px solid #0b0d0e;\n      border-radius: 50%;\n      animation: spin 1s linear infinite;\n    }\n\n    @keyframes spin {\n      0% { transform: rotate(0deg); }\n      100% { transform: rotate(360deg); }\n    }\n\n    /* Success State */\n    .success-icon {\n      color: #22c55e;\n      width: 48px;\n      height: 48px;\n      margin-bottom: 16px;\n      stroke-dasharray: 80;\n      stroke-dashoffset: 80;\n      animation: drawCheck 0.7s ease forwards;\n    }\n\n    .success-title {\n      font-size: 1.2rem;\n      font-weight: 600;\n      color: var(--ink-primary);\n      margin-bottom: 8px;\n    }\n\n    .success-desc {\n      font-size: 0.95rem;\n      color: var(--ink-secondary);\n      margin-bottom: 14px;\n      line-height: 1.5;\n    }\n\n    .success-email {\n      display: block;\n      margin-bottom: 24px;\n      padding: 10px 12px;\n      border: 1px solid var(--border-subtle);\n      border-radius: var(--radius-md);\n      background: rgba(11, 13, 14, 0.5);\n      color: var(--ink-primary);\n      font-size: 0.95rem;\n      overflow-wrap: anywhere;\n    }\n\n    .send-again {\n      color: var(--brand-primary);\n      font-size: 0.85rem;\n      text-decoration: none;\n      transition: opacity 0.2s;\n      background: none;\n      border: none;\n      min-height: 44px;\n      padding: 0 12px;\n      width: auto;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n    }\n\n    .send-again:hover {\n      opacity: 0.8;\n      background: none;\n    }\n\n    /* Rate Limit State */\n    .error-icon {\n      color: #ef4444;\n      width: 48px;\n      height: 48px;\n      margin-bottom: 16px;\n    }\n\n    .warning-icon {\n      color: #f59e0b;\n      width: 48px;\n      height: 48px;\n      margin-bottom: 16px;\n    }\n\n    .error-title {\n      font-size: 1.1rem;\n      font-weight: 500;\n      color: #ef4444;\n      margin-bottom: 8px;\n    }\n\n    .warning-title {\n      font-size: 1.1rem;\n      font-weight: 500;\n      color: #f59e0b;\n      margin-bottom: 8px;\n    }\n\n    .error-desc {\n      font-size: 0.9rem;\n      color: var(--ink-secondary);\n      margin-bottom: 24px;\n    }\n\n    .form-error {\n      color: #ef4444;\n      font-size: 0.85rem;\n      line-height: 1.4;\n      margin-bottom: 16px;\n      text-align: left;\n    }\n\n    .form-error[hidden] {\n      display: none;\n    }\n\n    @keyframes drawCheck {\n      to {\n        stroke-dashoffset: 0;\n      }\n    }\n\n    /* Mobile */\n    @media (max-width: 480px) {\n      body {\n        padding: 0;\n      }\n\n      .card {\n        padding: 28px 24px;\n        border-radius: 0;\n        border-left: none;\n        border-right: none;\n        min-height: 100vh;\n        min-height: 100svh;\n        display: flex;\n        flex-direction: column;\n        justify-content: center;\n      }\n\n      .logo-mark {\n        width: 52px;\n        height: 52px;\n      }\n\n      h1 {\n        font-size: 1.45rem;\n      }\n    }\n  </style>\n</head>\n<body>\n\n  <div class=\"card\">\n    <div class=\"logo-container\">\n      <svg class=\"logo-mark\" viewBox=\"0 0 100 100\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"4\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\" xmlns=\"http://www.w3.org/2000/svg\">\n        <path d=\"M20,80 Q50,40 50,20 Q50,40 80,80\" />\n        <path d=\"M50,20 L50,80\" stroke-dasharray=\"8 8\" />\n        <path d=\"M10,20 Q30,10 50,20 Q70,10 90,20 L90,80 Q70,70 50,80 Q30,70 10,80 Z\" stroke-width=\"3\" />\n      </svg>\n      <h1>LogOS Core</h1>\n      <div class=\"tagline\">The Operating System for Truth</div>\n      <div class=\"brand-divider\" aria-hidden=\"true\"></div>\n    </div>\n\n    <!-- State 1: Initial -->\n    <form id=\"state-initial\" class=\"state active\">\n      <div class=\"input-wrapper\">\n        <span class=\"email-label\">Email</span>\n        <input type=\"email\" placeholder=\"you@example.com\" id=\"email-input\" autocomplete=\"email\" required>\n      </div>\n      <div id=\"form-error\" class=\"form-error\" role=\"alert\" hidden>Unable to send login link. Try again later.</div>\n      <button id=\"btn-send\" type=\"submit\">Send Login Link</button>\n    </form>\n\n    <!-- State 2: Sending -->\n    <div id=\"state-sending\" class=\"state\" aria-live=\"polite\">\n      <div class=\"input-wrapper\">\n        <span class=\"email-label\">Email</span>\n        <input type=\"email\" id=\"sending-email\" value=\"\" disabled>\n      </div>\n      <button disabled>\n        <div class=\"spinner\"></div>\n      </button>\n    </div>\n\n    <!-- State 3: Success -->\n    <div id=\"state-success\" class=\"state\" aria-live=\"polite\">\n      <svg class=\"success-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n        <path d=\"M22 11.08V12a10 10 0 1 1-5.93-9.14\"></path>\n        <polyline points=\"22 4 12 14.01 9 11.01\"></polyline>\n      </svg>\n      <div class=\"success-title\">Check your email</div>\n      <div class=\"success-desc\">We sent a login link to your email address.</div>\n      <span id=\"success-email\" class=\"success-email\"></span>\n      <button class=\"send-again\" type=\"button\" data-reset>Send again</button>\n    </div>\n\n    <!-- State 4: Rate Limited -->\n    <div id=\"state-rate-limited\" class=\"state\" aria-live=\"polite\">\n      <svg class=\"warning-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n        <circle cx=\"12\" cy=\"12\" r=\"10\"></circle>\n        <line x1=\"12\" y1=\"8\" x2=\"12\" y2=\"12\"></line>\n        <line x1=\"12\" y1=\"16\" x2=\"12.01\" y2=\"16\"></line>\n      </svg>\n      <div class=\"warning-title\">Too many requests</div>\n      <div class=\"error-desc\">Please try again later.</div>\n      <button class=\"send-again\" type=\"button\" data-reset>Try again</button>\n    </div>\n\n  </div>\n\n  <script>\n    const form = document.getElementById('state-initial');\n    const emailInput = document.getElementById('email-input');\n    const sendingEmail = document.getElementById('sending-email');\n    const successEmail = document.getElementById('success-email');\n    const formError = document.getElementById('form-error');\n\n    function switchState(stateId) {\n      document.querySelectorAll('.state').forEach((el) => el.classList.remove('active'));\n      document.getElementById(stateId).classList.add('active');\n    }\n\n    function resetForm() {\n      formError.hidden = true;\n      switchState('state-initial');\n      emailInput.focus();\n    }\n\n    form.addEventListener('submit', async (event) => {\n      event.preventDefault();\n      formError.hidden = true;\n\n      if (!emailInput.reportValidity()) return;\n\n      const email = emailInput.value.trim();\n      sendingEmail.value = email;\n      successEmail.textContent = email;\n      switchState('state-sending');\n\n      try {\n        const response = await fetch('/api/auth/send', {\n          method: 'POST',\n          headers: { 'Content-Type': 'application/json' },\n          body: JSON.stringify({ email })\n        });\n\n        if (response.ok) {\n          switchState('state-success');\n          return;\n        }\n\n        if (response.status === 429) {\n          switchState('state-rate-limited');\n          return;\n        }\n\n        formError.textContent = 'Unable to send login link. Try again later.';\n        formError.hidden = false;\n        switchState('state-initial');\n      } catch {\n        formError.textContent = 'Unable to send login link. Try again later.';\n        formError.hidden = false;\n        switchState('state-initial');\n      }\n    });\n\n    document.querySelectorAll('[data-reset]').forEach((button) => {\n      button.addEventListener('click', resetForm);\n    });\n  </script>\n</body>\n</html>\n";
